async (params, browser) => {
  // Search X
  await browser.open('https://x.com/search')

  // Wait for page content
  await browser.waitForSelector('article[data-testid=\'tweet\']', 15000)

  // Let page settle
  await browser.wait(1000)

  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Like tweets from search results
  const result = await browser.evaluate(`const maxLikes = Math.min(parseInt('' + params.max_likes + '') || 5, 20); const likeButtons = document.querySelectorAll('[data-testid$="like"]'); let liked = 0; for (let i = 0; i < Math.min(likeButtons.length, maxLikes); i++) { likeButtons[i].click(); liked++; await new Promise(r => setTimeout(r, 800 + Math.random() * 700)); } return { liked_count: liked, message: \`Liked \${liked} tweets\` }`)

  return result
}
